UPDATE emp.tn_emp_oprtr_info
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE emp_plan_id = #{empPlanId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
